fact_path = "abfss://con-healthcare-proj@saazurepractice12.dfs.core.windows.net/gold/Fact_Patient_Visit"

if DeltaTable.isDeltaTable(spark, fact_path):

    delta_table = DeltaTable.forPath(spark, fact_path)

    delta_table.alias("target").merge(
        fact_final.alias("source"),
        "target.visit_id = source.visit_id"
    ).whenMatchedUpdate(set={
        "total_amount": "source.total_amount",
        "insurance_amount": "source.insurance_amount",
        "self_pay_amount": "source.self_pay_amount",
        "medicine_cost": "source.medicine_cost"
    }).whenNotMatchedInsertAll().execute()

else:
    fact_final.write.format("delta").save(fact_path)
